waves.point_eqs_str:
//rotating sphere

n = sample*6.283;

//draw circle, loop 32x
xp = sin(n*32);
yp = cos(n*32);
zp = 0;

//turn circle into sphere, by rotating on y axis once during frame
ang = n;
sang = sin(ang);cang = cos(ang);
xq = xp*cang - zp*sang;
yq = yp;
zq = xp*sang + zp*cang;
xp=xq;yp=yq;zp=zq;


//x axis rotation;
ang = t1;
sang = sin(ang);cang = cos(ang);
xq = xp;
yq = yp*cang - zp*sang;
zq = yp*sang + zp*cang;
xp=xq;yp=yq;zp=zq;

//y axis rotation;
ang = t1*2;
sang = sin(ang);cang = cos(ang);
xq = xp*cang - zp*sang;
yq = yp;
zq = xp*sang + zp*cang;
xp=xq;yp=yq;zp=zq;

//z axis rotation;
ang = t1*3;
sang = sin(ang);cang = cos(ang);
xq = xp*cang - yp*sang;
yq = xp*sang + yp*cang;
zq = zp;
xp=xq;yp=yq;zp=zq;

//push forward into viewspace
zp = zp + 4;

fov = 1; //larger number equal less extreme perspective (zoom in)

//project into camera space, and compensate for aspect ratio
x = xp/zp * fov + 0.5;
y = yp/zp * 1.3333 * fov + 0.5;
